/**
 * Tire une entree (mot + definition) dans la banque, en evitant celles deja
 * tirees dans la partie (par index) et en respectant la fourchette de
 * difficulte demandee. Si tout a ete tire, on repart de zero (mais en
 * gardant le filtre de difficulte).
 *
 * @param alreadyDrawn liste des index deja tires durant la partie
 * @param minDiff difficulte minimale acceptee (1-5, defaut 1)
 * @param maxDiff difficulte maximale acceptee (1-5, defaut 5)
 * @returns l'index tire et l'entree correspondante
 */
export function drawWord(
  alreadyDrawn: number[],
  minDiff: number = 1,
  maxDiff: number = 5
): { index: number; entry: WordEntry } {
  const matching = WORD_BANK
    .map((entry, i) => ({ entry, i }))
    .filter(({ entry }) => entry.difficulty >= minDiff && entry.difficulty <= maxDiff);
  const candidates = matching.filter(({ i }) => !alreadyDrawn.includes(i));
  // Si on a deja epuise la sous-banque filtree, on repart sur l'ensemble filtre.
  const pool = candidates.length > 0 ? candidates : matching;
  if (pool.length === 0) {
    // Cas degenere : fourchette de difficulte qui ne matche rien.
    // Fallback sur la banque complete pour ne pas casser la partie.
    const allIndices = WORD_BANK.map((_, i) => i);
    const remaining = allIndices.filter((i) => !alreadyDrawn.includes(i));
    const fallback = remaining.length > 0 ? remaining : allIndices;
    const buf = new Uint16Array(1);
    crypto.getRandomValues(buf);
    const index = fallback[buf[0] % fallback.length];
    return { index, entry: WORD_BANK[index] };
  }
  const buf = new Uint16Array(1);
  crypto.getRandomValues(buf);
  const picked = pool[buf[0] % pool.length];
  return { index: picked.i, entry: picked.entry };
}
